    def maxValue(self, n: int, index: int, maxSum: int) -> int:
        nums = [0] * n
        left_sum = 0
        right_sum = maxSum - left_sum
        for i in range(n):
            if i == index:
                nums[i] = min(right_sum, maxSum - left_sum)
            else:
                nums[i] = min(left_sum + 1, right_sum - 1)
            if i < index:
                left_sum += nums[i]
            else:
                right_sum -= nums[i]
